@app.route('/reset-mfa', methods=['GET', 'POST'])
def reset_mfa():
    if request.method == 'POST':
        email = request.form['email']
        user = User.query.filter_by(email=email).first()
        if user:
            token = serializer.dumps({'user_id': user.id})
            link = url_for('reset_mfa_confirm', token=token, _external=True)
            message = Message('MFA Reset Link', sender='your_email@example.com', recipients=[email])
            message.body = f'Click the following link to reset your MFA settings: {link}'
            mail.send(message)
            return 'An email with a reset link has been sent to your registered email address.'
    return render_template('reset_mfa.html')

@app.route('/reset-mfa-confirm/<token>')
def reset_mfa_confirm(token):
    try:
        data = serializer.loads(token)
        user_id = data['user_id']
        user = User.query.get(user_id)
        user.mfa_enabled = False
        db.session.commit()
        return 'Your MFA settings have been reset. You can now log in with just your password.'
    except:
        return 'Invalid token.'

